var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"RIFLE_FOX_ENEMY_NULL","text":{"KOREA":"포기하지 마라! 타겟을 반드시 확보해야 한다!","JPN":"諦めるな！　ターゲットを必ず確保しなければならない！","ENG":"Don't give up! We must secure the target at all costs!","TWN":"不可以放棄！一定要帶走目標！"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":null,"C":{"char_id":"RIFLE_FOX_ENEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"적의 공세가 잦아들 기미가 없네요.","JPN":"敵の攻勢が一向に衰えません。","ENG":"They wouldn't stop coming.","TWN":"敵人的攻勢越來越緊密了。"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그 여자애가 누구길래 저 사람들이 납치하려고 하는 건가요?","JPN":"彼らがここまでして拉致しようとしているあの女の子は、一体何者なのですか？","ENG":"Who is this girl? And why do they want her?","TWN":"那個女孩是誰，那些人為什麼要綁架她？"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"하아, 일종의 스카우트 제안이라고 보시면 될 것 같네요.","JPN":"はぁ、一種のスカウトだと思っていただければ。","ENG":"*Sigh* This, in a way, is a job offer.","TWN":"唉，這應該可以看作是一個挖角提議吧。"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"이디스는 로봇공학과 인공지능 분야에서 세계 최고라 할 수 있는 기술자거든요.","JPN":"イーディスはロボット工学と人工知能の分野で、世界トップと言える技術者ですから。","ENG":"Edith is the world's best when it comes to robotics and artificial intelligence.","TWN":"伊蒂絲擁有機器人工學和人工智慧領域的世界頂尖技術。"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"어떤 방법을 써서라도 이디스를 데려가고 싶어 하는 기업이나 단체들이 많죠.","JPN":"どんな方法を使ってでもイーディスを手に入れたいという企業や団体は後を絶ちません。","ENG":"Numerous companies and organizations are desperate to recruit her into their midst.","TWN":"所以有很多公司就算不擇手段，也都想要帶走伊蒂絲。"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"하지만 인재 영입이라고 보기엔 방식이 살짝 과격한 것 같은데요?","JPN":"でも、スカウトにしては少し過激ではありませんか？","ENG":"But this is way too rough to be a job offer.","TWN":"但這個挖角方式也太激烈了吧？"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"이렇게 무리한 방법 대신 정정당당하게 현찰과 복지로 승부하는 게 낫지 않을까요?","JPN":"こんな強奪するようなやり方より、正々堂々とお金と福利厚生で勝負した方がいいと思いますけど。","ENG":"Can't they offer her money and benefits instead?","TWN":"比起用這種不講理的方法，用公平的報酬和福利來談不是更好嗎？"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"그런 제안은 이미 여러 차례 거절했어요.","JPN":"そのような提案は、すでに断ってしまったので。","ENG":"They tried. Several times.","TWN":"那種提議已經被拒絕多次了。"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"이디스는 악당과 악덕기업이라면 아무리 많은 돈을 줘도 싫어하거든요.","JPN":"イーディスは悪党や悪徳企業には、いくらお金を出されても行きたくないそうです。","ENG":"Edith will never work for villains or unethical corporations, no matter how much money they offer.","TWN":"只要是壞蛋和黑心企業，不管給再多錢伊蒂絲都不願意接受。"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"저도 아카데미의 학생이 원치 않는 일을 강제로 하는 것은 어떻게 해서든 막을 거고요.","JPN":"私もアカデミーの学生を強制的に望まない道に進ませるのは、どんな手を使ってでも阻止するつもりです。","ENG":"With all my force, I'm not going to let anyone coerce my students, either.","TWN":"我也不希望學院的學生被人強迫，去做自己不喜歡的事情。"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"하지만 이렇게 노골적으로 군대를 끌고 올 줄은 몰랐네요. 제 불찰이에요.","JPN":"しかし、こんな風に露骨に軍隊を引き連れてくるとは思いませんでした。私の不徳の致すところです。","ENG":"But I never thought they'd openly send armies like this. This is my fault.","TWN":"但沒想到對方會明目張膽地派軍隊來搶人，是我大意了。"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"잠깐! 이디스? 그럼 설마 이디스 트윈즈야?","JPN":"ちょっと待ってください！　イーディス？　それってまさか、イーディス・ツインズ？","ENG":"Wait! Edith? Are you talking about Edith Twins?","TWN":"等一下！妳說伊蒂絲？該不會是伊蒂絲雙子吧？"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"이 잠 밖에 모르는 꼬마가 월드매거진에 소개됐던 그 유명한 퓨처 앳 워 최연소 수석 연구원이라고?","JPN":"この暇さえあれば寝てる子が、ワールドマガジンに紹介されたあの有名なフューチャーアットウォー最年少首席研究員？","ENG":"This little sleepyhead is the youngest senior researcher ever at Future-at-War, featured in World Magazine?","TWN":"這個只知道睡覺的小鬼，竟然是世界雜誌介紹的那位著名的天啟兵器最年輕首席研究員？"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CHAIR_SCHOOL_SUMMER_NULL","text":{"KOREA":"으음...... 아기물개...... 너무 귀여워......","JPN":"う～ん……オットセイの赤ちゃん……すごくカワイイ……","ENG":"Mm... Baby seals... So cute...","TWN":"嗯……小海狗……好可愛……"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RIFLE_FOX_ENEMY_NULL","text":{"KOREA":"저쪽에 있다! 무조건 잡아!","JPN":"あっちにいたぞ！　何があっても逃すな！","ENG":"Over there! Catch her, no matter what!","TWN":"在那裡！不管怎麼樣都要抓到她！"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":null,"C":{"char_id":"RIFLE_FOX_ENEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"아무래도 싸움이 길어질 것 같네요.","JPN":"やはり、戦いは長引きそうですね。","ENG":"This is going to be a long fight.","TWN":"看來會是一場持久戰。"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"여러분은 여기서 피하세요.","JPN":"皆さんはここから逃げてください。","ENG":"You should leave.","TWN":"你們快離開這裡。"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};